import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';

// Styled Components

const LoginCard = styled.div`
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(10px);
  border-radius: 24px;
  padding: 2rem;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
  width: 100%;
  max-width: 400px;
  margin: 1rem;
`;

const Title = styled.h1`
  font-size: 2.5rem;
  font-weight: bold;
  color: #374151;
  text-align: center;
  margin-bottom: 0.5rem;
`;

const Subtitle = styled.p`
  color: #6b7280;
  font-size: 0.875rem;
  text-align: center;
  margin-bottom: 2rem;
`;

const InputField = styled.input`
  width: 100%;
  padding: 0.75rem 1rem;
  border-radius: 50px;
  border: 1px solid #d1d5db;
  outline: none;
  color: #374151;
  margin-bottom: 1rem;
  
  &::placeholder {
    color: #9ca3af;
  }
  
  &:focus {
    border-color: #a855f7;
    box-shadow: 0 0 0 3px rgba(168, 85, 247, 0.1);
  }
`;

const LoginButton = styled.button`
  width: 100%;
  background: #a855f7;
  color: white;
  font-weight: 600;
  padding: 0.75rem 1rem;
  border-radius: 50px;
  border: none;
  cursor: pointer;
  transition: all 0.2s ease-in-out;
  margin-bottom: 1rem;
  
  &:hover {
    background: #9333ea;
    transform: scale(1.02);
  }
  
  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none;
  }
`;

const GoogleButton = styled.button`
  width: 100%;
  background: white;
  color: #374151;
  font-weight: 600;
  padding: 0.75rem 1rem;
  border-radius: 50px;
  border: 1px solid #d1d5db;
  cursor: pointer;
  transition: all 0.2s ease-in-out;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  
  &:hover {
    background: #f9fafb;
    transform: scale(1.02);
  }
  
  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none;
  }
`;

const Divider = styled.div`
  display: flex;
  align-items: center;
  margin: 1.5rem 0;
  
  &::before,
  &::after {
    content: '';
    flex: 1;
    height: 1px;
    background: #d1d5db;
  }
  
  span {
    padding: 0 1rem;
    color: #6b7280;
    font-size: 0.875rem;
  }
`;

const LinkSection = styled.div`
  margin-top: 1.5rem;
  text-align: center;
  
  a {
    color: #6b7280;
    font-size: 0.875rem;
    text-decoration: none;
    display: block;
    margin-bottom: 0.5rem;
    
    &:hover {
      color: #a855f7;
    }
  }
  
  .signup-link {
    color: #a855f7;
    
    &:hover {
      color: #9333ea;
    }
  }
`;

const LoginPage = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Google 로그인 초기화
  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://accounts.google.com/gsi/client';
    script.async = true;
    script.defer = true;
    document.body.appendChild(script);

    script.onload = () => {
      console.log('Google Identity Services loaded');
      // 실제 구현 시:
      // window.google?.accounts.id.initialize({
      //   client_id: process.env.REACT_APP_GOOGLE_CLIENT_ID,
      //   callback: handleGoogleResponse
      // });
    };

    return () => {
      if (document.body.contains(script)) {
        document.body.removeChild(script);
      }
    };
  }, []);

  const handleGoogleResponse = (response) => {
    console.log('Google JWT:', response.credential);
    // JWT 토큰을 서버에 전송하여 검증
    // 성공 시 navigate를 사용하여 리다이렉트
    navigate('/dashboard'); // 예시
  };

  const handleGoogleLogin = () => {
    setIsLoading(true);
    
    // 실제 Google 로그인 구현
    // window.google?.accounts.id.prompt();
    
    // 데모용 - 실제로는 위 코드를 사용
    console.log('Google 로그인 시도');
    setTimeout(() => {
      setIsLoading(false);
      alert('Google 로그인 연동이 필요합니다. 실제 구현 시 Google Client ID와 콜백 함수를 설정해주세요.');
      // navigate('/dashboard'); // 성공 시 이동
    }, 1000);
  };

  const handleEmailLogin = () => {
    if (!email || !password) {
      alert('이메일과 비밀번호를 입력해주세요.');
      return;
    }

    setIsLoading(true);
    
    // 서버에 로그인 요청
    console.log('이메일 로그인:', { email, password });
    
    // 데모용 - 실제로는 API 호출
    setTimeout(() => {
      setIsLoading(false);
      alert('로그인 성공! (데모)');
      navigate('/dashboard'); // 성공 시 대시보드로 이동
    }, 1000);
  };

  const handleForgotPassword = () => {
    navigate('/forgot-password');
  };

  const handleSignUp = () => {
    navigate('/signup');
  };

  return (
    <>
      <LoginContainer>
        <LoginCard>
          {/* 제목 */}
          <Title>LOGIN</Title>
          <Subtitle>로그인 해주세요</Subtitle>

          {/* 이메일 입력 */}
          <InputField
            type="email"
            placeholder="이메일을 입력하세요"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />

          {/* 비밀번호 입력 */}
          <InputField
            type="password"
            placeholder="비밀번호를 입력하세요"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          {/* 일반 로그인 버튼 */}
          <LoginButton
            onClick={handleEmailLogin}
            disabled={isLoading}
          >
            {isLoading ? '로그인 중...' : '로그인'}
          </LoginButton>

          {/* 구분선 */}
          <Divider>
            <span>또는</span>
          </Divider>

          {/* Google 로그인 버튼 */}
          <GoogleButton
            onClick={handleGoogleLogin}
            disabled={isLoading}
          >
            <svg width="20" height="20" viewBox="0 0 24 24">
              <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
              <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
              <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
              <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
            </svg>
            Google로 로그인
          </GoogleButton>

          {/* 추가 링크들 */}
          <LinkSection>
            <a href="#" onClick={handleForgotPassword}>비밀번호를 잊으셨나요?</a>
            <div style={{ fontSize: '0.875rem', color: '#6b7280' }}>
              계정이 없으신가요? 
              <a href="#" onClick={handleSignUp} className="signup-link" style={{ marginLeft: '0.25rem' }}>
                회원가입
              </a>
            </div>
          </LinkSection>
        </LoginCard>
      </LoginContainer>
    </>
  );
};

export default LoginPage;
